test_cases.python_test_script:
def test_tc_gw_001_horn_on(can_bus):
    msgs = collect_messages(can_bus, GW_SYSTEM_OVERVIEW_ID)
    assert msgs
    for msg in msgs:
        assert decode_gws_horn_active(msg) == 1

def test_tc_gw_002_horn_off(can_bus):
    msgs = collect_messages(can_bus, GW_SYSTEM_OVERVIEW_ID)
    assert msgs
    for msg in msgs:
        assert decode_gws_horn_active(msg) == 0

def test_tc_gw_003_indicator_left(can_bus):
    msgs = collect_messages(can_bus, GW_SYSTEM_OVERVIEW_ID)
    assert msgs
    for msg in msgs:
        assert decode_gws_indicator_state(msg) == 1
